CREATE OR REPLACE FUNCTION fpa_fin_pay_sign ( as_vourcher_no text , ai_seq integer ) RETURNS integer AS $body$
DECLARE

  li_sign bigint;

BEGIN

  SELECT CASE WHEN  coalesce( sum(sc_fin_vourcher_detail.item_amount) , 0 ) =0 THEN  1   ELSE -1 END   into STRICT li_sign
  FROM sc_fin_vourcher_detail
  where sc_fin_vourcher_detail.vourcher_no = as_vourcher_no
  and sc_fin_vourcher_detail.seq_no = ai_seq
  and sc_fin_vourcher_detail.account_tr in ('2142015','2141070','2141090','2141095','2142010')
;

  return  li_sign;

exception when others then return 0;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
